import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Ajouter un compte: double canal OAuth et Refresh Token | Antigravity Tools","description":"Apprenez à ajouter des comptes dans Antigravity Tools via OAuth ou Refresh Token. Support d'import en lot, gestion des échecs de callback et vérification du pool.","frontmatter":{"title":"Ajouter un compte: double canal OAuth et Refresh Token | Antigravity Tools","sidebarTitle":"Ajouter votre compte Google","subtitle":"Ajouter un compte : double canal OAuth/Refresh Token et bonnes pratiques","description":"Apprenez à ajouter des comptes dans Antigravity Tools via OAuth ou Refresh Token. Support d'import en lot, gestion des échecs de callback et vérification du pool.","tags":["Gestion de comptes","OAuth","refresh_token","Google","Bonnes pratiques"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/start/add-account/index.md"}`),n={name:"fr/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function i(l,e,u,c,s,d){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="ajouter-un-compte-double-canal-oauth-refresh-token-et-bonnes-pratiques" tabindex="-1">Ajouter un compte : double canal OAuth/Refresh Token et bonnes pratiques <a class="header-anchor" href="#ajouter-un-compte-double-canal-oauth-refresh-token-et-bonnes-pratiques" aria-label="Permalink to &quot;Ajouter un compte : double canal OAuth/Refresh Token et bonnes pratiques&quot;">​</a></h1><p>Dans Antigravity Tools, &quot;ajouter un compte&quot; signifie écrire le <code>refresh_token</code> du compte Google dans le pool de comptes local, permettant aux requêtes de proxy inversé de les utiliser en rotation. Vous pouvez passer par l&#39;autorisation OAuth en un clic, ou coller directement le <code>refresh_token</code> pour un ajout manuel.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>Ajouter des comptes Google au pool de comptes d&#39;Antigravity Tools via OAuth ou Refresh Token</li><li>Copier/ouvrir manuellement le lien d&#39;autorisation, et compléter automatiquement l&#39;ajout après un callback réussi</li><li>Savoir comment résoudre des problèmes comme l&#39;impossibilité d&#39;obtenir un <code>refresh_token</code> ou l&#39;échec de connexion du callback à <code>localhost</code></li></ul><h2 id="vos-difficultes-actuelles" tabindex="-1">Vos difficultés actuelles <a class="header-anchor" href="#vos-difficultes-actuelles" aria-label="Permalink to &quot;Vos difficultés actuelles&quot;">​</a></h2><ul><li>Vous avez cliqué sur &quot;Autorisation OAuth&quot; mais l&#39;indicateur tourne en rond, ou le navigateur indique <code>localhost refused to connect</code></li><li>L&#39;autorisation a réussi, mais un message indique &quot;Refresh Token non obtenu&quot;</li><li>Vous avez uniquement le <code>refresh_token</code> en main et ne savez pas comment l&#39;importer en lot</li></ul><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand utiliser cette méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand utiliser cette méthode&quot;">​</a></h2><ul><li>Vous voulez ajouter des comptes de la manière la plus stable (priorité à OAuth)</li><li>Vous privilégiez la portabilité/sauvegarde (Refresh Token est plus adapté comme &quot;actif de pool de comptes&quot;)</li><li>Vous devez ajouter de nombreux comptes et souhaitez importer des <code>refresh_token</code> en lot (extraction à partir de texte/JSON supportée)</li></ul><h2 id="🎒-preparatifs-avant-de-commencer" tabindex="-1">🎒 Préparatifs avant de commencer <a class="header-anchor" href="#🎒-preparatifs-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparatifs avant de commencer&quot;">​</a></h2><ul><li>Vous avez installé et pouvez ouvrir l&#39;application de bureau Antigravity Tools</li><li>Vous savez où trouver l&#39;entrée : dans la navigation de gauche, allez à la page <code>Accounts</code> (route voir <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code>)</li></ul><div class="info custom-block"><p class="custom-block-title">Deux mots-clés dans ce cours</p><p><strong>OAuth</strong> : Un processus &quot;se connecter et autoriser via le navigateur&quot;. Antigravity Tools lance temporairement une adresse de callback locale (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, choisie automatiquement selon la surveillance IPv4/IPv6 du système), attend que le navigateur revienne avec un <code>code</code>, puis l&#39;échange contre un token. (Implémentation voir <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code>)</p><p><strong>refresh_token</strong> : Un &quot;identifiant permettant de rafraîchir l&#39;access_token sur le long terme&quot;. Lors de l&#39;ajout de comptes dans ce projet, il est utilisé pour obtenir d&#39;abord un access_token, puis récupérer l&#39;adresse email réelle auprès de Google, et l&#39;email que vous avez saisi en frontend est ignoré. (Implémentation voir <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code>)</p></div><h2 id="idee-principale" tabindex="-1">Idée principale <a class="header-anchor" href="#idee-principale" aria-label="Permalink to &quot;Idée principale&quot;">​</a></h2><p>&quot;Ajouter un compte&quot; dans Antigravity Tools vise finalement à obtenir un <code>refresh_token</code> utilisable et à écrire les informations du compte dans le pool de comptes local.</p><ul><li><strong>Canal OAuth</strong> : L&#39;application génère le lien d&#39;autorisation pour vous et surveille le callback local ; après l&#39;autorisation, elle échange automatiquement le token et sauvegarde le compte (voir <code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code>)</li><li><strong>Canal Refresh Token</strong> : Vous collez directement le <code>refresh_token</code>, l&#39;application l&#39;utilise pour rafraîchir l&#39;access_token, et récupère l&#39;adresse email réelle auprès de Google pour la sauvegarder (voir <code>add_account</code>)</li></ul><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-ouvrir-la-fenetre-ajouter-un-compte" tabindex="-1">Étape 1 : Ouvrir la fenêtre &quot;Ajouter un compte&quot; <a class="header-anchor" href="#etape-1-ouvrir-la-fenetre-ajouter-un-compte" aria-label="Permalink to &quot;Étape 1 : Ouvrir la fenêtre &quot;Ajouter un compte&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Tous les points d&#39;ajout sont centralisés sur la page <code>Accounts</code>.</p><p>Action : Allez à la page <code>Accounts</code> et cliquez sur le bouton <strong>Add Account</strong> à droite (composant : <code>AddAccountDialog</code>).</p><p><strong>Ce que vous devriez voir</strong> : Une fenêtre apparaît avec 3 onglets : <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (voir <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code>).</p><h3 id="etape-2-prioriser-l-autorisation-oauth-en-un-clic-recommande" tabindex="-1">Étape 2 : Prioriser l&#39;autorisation OAuth en un clic (recommandé) <a class="header-anchor" href="#etape-2-prioriser-l-autorisation-oauth-en-un-clic-recommande" aria-label="Permalink to &quot;Étape 2 : Prioriser l&#39;autorisation OAuth en un clic (recommandé)&quot;">​</a></h3><p><strong>Pourquoi</strong> C&#39;est le chemin recommandé par défaut du produit : laisser l&#39;application générer le lien d&#39;autorisation, ouvrir automatiquement le navigateur, et compléter automatiquement la sauvegarde après le callback.</p><ol><li>Allez à l&#39;onglet <code>OAuth</code>.</li><li>Copiez d&#39;abord le lien d&#39;autorisation : après l&#39;ouverture de la fenêtre, <code>prepare_oauth_url</code> est appelé automatiquement pour pré-générer l&#39;URL (appel frontend voir <code>AddAccountDialog.tsx:111-125</code> ; génération backend et surveillance voir <code>oauth_server.rs</code>).</li><li>Cliquez sur <strong>Start OAuth</strong> (correspondant au frontend <code>startOAuthLogin()</code> / backend <code>start_oauth_login</code>), l&#39;application ouvre le navigateur par défaut et commence à attendre le callback.</li></ol><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Un lien d&#39;autorisation copiable apparaît dans la fenêtre (nom de l&#39;événement : <code>oauth-url-generated</code>)</li><li>Le navigateur ouvre la page d&#39;autorisation Google ; après l&#39;autorisation, il redirige vers une adresse locale et affiche &quot;Authorization Successful!&quot; (<code>oauth_success_html()</code>)</li></ul><h3 id="etape-3-quand-oauth-ne-s-acheve-pas-automatiquement-utilisez-finish-oauth-pour-terminer-manuellement" tabindex="-1">Étape 3 : Quand OAuth ne s&#39;achève pas automatiquement, utilisez &quot;Finish OAuth&quot; pour terminer manuellement <a class="header-anchor" href="#etape-3-quand-oauth-ne-s-acheve-pas-automatiquement-utilisez-finish-oauth-pour-terminer-manuellement" aria-label="Permalink to &quot;Étape 3 : Quand OAuth ne s&#39;achève pas automatiquement, utilisez &quot;Finish OAuth&quot; pour terminer manuellement&quot;">​</a></h3><p><strong>Pourquoi</strong> Le processus OAuth se fait en deux étapes : le navigateur obtient un <code>code</code> par autorisation, puis l&#39;application utilise le <code>code</code> pour échanger un token. Même si vous n&#39;avez pas cliqué sur &quot;Start OAuth&quot;, tant que vous avez ouvert manuellement le lien d&#39;autorisation et terminé le callback, la fenêtre essaiera de terminer automatiquement ; si cela échoue, vous pouvez cliquer manuellement une fois.</p><ol><li>Si vous avez &quot;copié le lien et l&#39;avez ouvert dans votre propre navigateur&quot; (au lieu du navigateur par défaut), après le callback d&#39;autorisation, l&#39;application recevra l&#39;événement <code>oauth-callback-received</code> et appellera automatiquement <code>completeOAuthLogin()</code> (voir <code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code>).</li><li>Si vous ne voyez pas l&#39;achèvement automatique, cliquez sur <strong>Finish OAuth</strong> dans la fenêtre (correspondant au backend <code>complete_oauth_login</code>).</li></ol><p><strong>Ce que vous devriez voir</strong> : La fenêtre indique le succès et se ferme automatiquement ; le nouveau compte apparaît dans la liste <code>Accounts</code>.</p><div class="tip custom-block"><p class="custom-block-title">Astuce : En cas d&#39;échec de callback, copiez d&#39;abord le lien</p><p>Le backend essaiera de surveiller simultanément IPv6 <code>::1</code> et IPv4 <code>127.0.0.1</code>, et choisira <code>localhost/127.0.0.1/[::1]</code> comme adresse de callback selon la situation de surveillance, principalement pour éviter les échecs de connexion causés par &quot;le navigateur résolvant localhost en IPv6&quot;. (Voir <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>)</p></div><h3 id="etape-4-ajouter-manuellement-avec-refresh-token-support-en-lot" tabindex="-1">Étape 4 : Ajouter manuellement avec Refresh Token (support en lot) <a class="header-anchor" href="#etape-4-ajouter-manuellement-avec-refresh-token-support-en-lot" aria-label="Permalink to &quot;Étape 4 : Ajouter manuellement avec Refresh Token (support en lot)&quot;">​</a></h3><p><strong>Pourquoi</strong> Quand vous ne pouvez pas obtenir de <code>refresh_token</code> (ou si vous préférez &quot;un actif portable&quot;), l&#39;ajout direct avec Refresh Token est plus contrôlable.</p><ol><li>Allez à l&#39;onglet <code>Refresh Token</code>.</li><li>Collez le <code>refresh_token</code> dans la zone de texte.</li></ol><p>Formats d&#39;entrée supportés (le frontend analysera et ajoutera en lot) :</p><table tabindex="0"><thead><tr><th>Type d&#39;entrée</th><th>Exemple</th><th>Logique d&#39;analyse</th></tr></thead><tbody><tr><td>Texte token pur</td><td><code>1//abc...</code></td><td>Extraction par regex : <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (voir <code>AddAccountDialog.tsx:213-220</code>)</td></tr><tr><td>Inclus dans un long texte</td><td>Les logs/textes exportés contiennent plusieurs <code>1//...</code></td><td>Extraction par regex en lot et déduplication (voir <code>AddAccountDialog.tsx:213-224</code>)</td></tr><tr><td>Tableau JSON</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>Analyse le tableau et prend <code>item.refresh_token</code> (voir <code>AddAccountDialog.tsx:198-207</code>)</td></tr></tbody></table><p>Après avoir cliqué sur <strong>Confirm</strong>, la fenêtre appellera <code>onAdd(&quot;&quot;, token)</code> individuellement pour chaque token (voir <code>AddAccountDialog.tsx:231-248</code>), aboutissant finalement au backend <code>add_account</code>.</p><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>La fenêtre affiche la progression en lot (par exemple <code>1/5</code>)</li><li>Après succès, le nouveau compte apparaît dans la liste <code>Accounts</code></li></ul><h3 id="etape-5-confirmer-le-pool-de-comptes-est-utilisable" tabindex="-1">Étape 5 : Confirmer &quot;le pool de comptes est utilisable&quot; <a class="header-anchor" href="#etape-5-confirmer-le-pool-de-comptes-est-utilisable" aria-label="Permalink to &quot;Étape 5 : Confirmer &quot;le pool de comptes est utilisable&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> L&#39;ajout réussi ne signifie pas &quot;immédiatement utilisable de manière stable&quot;. Le backend déclenchera automatiquement un &quot;rafraîchissement de quota&quot; après l&#39;ajout, et essaiera de recharger le token pool lors de l&#39;exécution du Proxy, rendant les modifications effectives immédiatement.</p><p>Vous pouvez confirmer avec les 2 signaux suivants :</p><ol><li>Le compte apparaît dans la liste et affiche l&#39;email (l&#39;email vient du backend <code>get_user_info</code>, pas de l&#39;email que vous avez saisi).</li><li>Les informations de quota/souscription du compte commencent à se rafraîchir (le backend appellera automatiquement <code>internal_refresh_account_quota</code>).</li></ol><p><strong>Ce que vous devriez voir</strong> : Après l&#39;ajout, il n&#39;est pas nécessaire de cliquer manuellement sur rafraîchir, les informations de quota commenceront à apparaître sur le compte (le succès ou non est basé sur l&#39;affichage réel de l&#39;interface).</p><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><ul><li>Vous pouvez voir l&#39;email du nouveau compte dans la liste de comptes</li><li>Aucun état &quot;loading&quot; ne persiste au-delà du temps acceptable (après l&#39;achèvement du callback OAuth, cela devrait se terminer rapidement)</li><li>Si vous exécutez le Proxy, le nouveau compte peut rapidement participer à l&#39;ordonnancement (le backend essaiera de recharger)</li></ul><h2 id="attention-aux-pieges" tabindex="-1">Attention aux pièges <a class="header-anchor" href="#attention-aux-pieges" aria-label="Permalink to &quot;Attention aux pièges&quot;">​</a></h2><h3 id="_1-oauth-indique-refresh-token-non-obtenu" tabindex="-1">1) OAuth indique &quot;Refresh Token non obtenu&quot; <a class="header-anchor" href="#_1-oauth-indique-refresh-token-non-obtenu" aria-label="Permalink to &quot;1) OAuth indique &quot;Refresh Token non obtenu&quot;&quot;">​</a></h3><p>Le backend dans <code>start_oauth_login/complete_oauth_login</code> vérifie explicitement si le <code>refresh_token</code> existe ; s&#39;il n&#39;existe pas, il renvoie un message d&#39;erreur avec une solution (voir <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code>).</p><p>Suivez la méthode de traitement suggérée par le code source :</p><ol><li>Ouvrez <code>https://myaccount.google.com/permissions</code></li><li>Révoquez les permissions d&#39;<strong>Antigravity Tools</strong></li><li>Retournez à l&#39;application et refaites OAuth</li></ol><blockquote><p>Vous pouvez aussi directement passer au canal Refresh Token de ce cours.</p></blockquote><h3 id="_2-le-navigateur-indique-localhost-refused-to-connect" tabindex="-1">2) Le navigateur indique <code>localhost refused to connect</code> <a class="header-anchor" href="#_2-le-navigateur-indique-localhost-refused-to-connect" aria-label="Permalink to &quot;2) Le navigateur indique `localhost refused to connect`&quot;">​</a></h3><p>Le callback OAuth nécessite que le navigateur demande l&#39;adresse de callback locale. Pour réduire le taux d&#39;échec, le backend :</p><ul><li>Essaie de surveiller simultanément <code>127.0.0.1</code> et <code>::1</code></li><li>N&#39;utilise <code>localhost</code> que lorsque les deux sont disponibles, sinon force l&#39;utilisation de <code>127.0.0.1</code> ou <code>[::1]</code></li></ul><p>L&#39;implémentation correspondante voir <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code>.</p><h3 id="_3-passer-a-un-autre-onglet-annule-la-preparation-oauth" tabindex="-1">3) Passer à un autre onglet annule la préparation OAuth <a class="header-anchor" href="#_3-passer-a-un-autre-onglet-annule-la-preparation-oauth" aria-label="Permalink to &quot;3) Passer à un autre onglet annule la préparation OAuth&quot;">​</a></h3><p>Lorsque la fenêtre passe de <code>OAuth</code> à un autre onglet, le frontend appellera <code>cancelOAuthLogin()</code> et videra l&#39;URL (voir <code>AddAccountDialog.tsx:127-136</code>).</p><p>Si vous êtes en cours d&#39;autorisation, ne vous précipitez pas pour changer d&#39;onglet.</p><h3 id="_4-exemples-corrects-incorrects-de-refresh-token" tabindex="-1">4) Exemples corrects/incorrects de Refresh Token <a class="header-anchor" href="#_4-exemples-corrects-incorrects-de-refresh-token" aria-label="Permalink to &quot;4) Exemples corrects/incorrects de Refresh Token&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Exemple</th><th>Reconnaissable</th><th>Raison</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td>Conforme à la règle de préfixe <code>1//</code> (voir <code>AddAccountDialog.tsx:215-219</code>)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>Non conforme à la règle d&#39;extraction frontend, sera considéré comme une entrée invalide</td></tr></tbody></table><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><ul><li>OAuth : adapté pour &quot;rapide&quot;, supporte aussi copier le lien vers votre navigateur habituel et terminer automatiquement/manuellement</li><li>Refresh Token : adapté pour &quot;stable&quot; et &quot;portable&quot;, supporte l&#39;extraction en lot <code>1//...</code> à partir de texte/JSON</li><li>Quand vous ne pouvez pas obtenir de <code>refresh_token</code>, révoquez l&#39;autorisation selon l&#39;invite d&#39;erreur et recommencez, ou passez directement au Refresh Token</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><p>Dans le prochain cours, nous allons faire quelque chose de plus concret : transformer le pool de comptes en &quot;actif portable&quot;.</p><blockquote><p>Allez apprendre <strong><a href="./../backup-migrate/">Sauvegarde et migration de comptes : import/export, migration à chaud V1/DB</a></strong>.</p></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquer pour déplier et voir les emplacements du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Page Accounts avec fenêtre d&#39;ajout montée</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Événement callback OAuth déclenche <code>completeOAuthLogin()</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Analyse et déduplication en lot Refresh Token</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>Appel frontend des commandes Tauri (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>Backend add_account : ignore email, utilise refresh_token pour obtenir email réel et sauvegarde</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>Backend OAuth : vérifie absence refresh_token et donne solution de révocation autorisation</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>Server callback OAuth : surveillance simultanée IPv4/IPv6 et choix redirect_uri</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Noms d&#39;événements clés</strong> :</p><ul><li><code>oauth-url-generated</code> : le backend envoie l&#39;URL OAuth au frontend après génération (voir <code>oauth_server.rs:250-252</code>)</li><li><code>oauth-callback-received</code> : le backend notifie le frontend après avoir reçu le callback et analysé le code (voir <code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code>)</li></ul><p><strong>Commandes clés</strong> :</p><ul><li><code>prepare_oauth_url</code> : pré-génère le lien d&#39;autorisation et lance la surveillance du callback (voir <code>src-tauri/src/commands/mod.rs:469-473</code>)</li><li><code>start_oauth_login</code> : ouvre le navigateur par défaut et attend le callback (voir <code>src-tauri/src/commands/mod.rs:339-401</code>)</li><li><code>complete_oauth_login</code> : n&#39;ouvre pas le navigateur, attend seulement le callback et complète l&#39;échange de token (voir <code>src-tauri/src/commands/mod.rs:405-467</code>)</li><li><code>add_account</code> : sauvegarde le compte avec refresh_token (voir <code>src-tauri/src/commands/mod.rs:19-60</code>)</li></ul></details>',67)])])}const h=t(n,[["render",i]]);export{m as __pageData,h as default};
